tests:
def test_plain_text():
    engine = TemplateEngine()
    assert engine.render('Hello World', {}) == 'Hello World'

def test_nested_for_with_objects():
    engine = TemplateEngine()
    ctx = {'users': [{'name': 'Alice'}, {'name': 'Bob'}]}
    result = engine.render('{% for user in users %}{{ user.name }},{% endfor %}', ctx)
    assert result == 'Alice,Bob,'
